import "./index.css";
import usefetch from './fetchdata.js'; // your custom hook
import { Link } from "react-router-dom";
import Yello from "./Yettostart.js";
import InProgress from "./Inprogress.js"

const Homepage = () => {
  const { Data, Ispending , Iserror} = usefetch("http://localhost:8000/TaskUploads")

  return (
    <div className="homepage">
        {Ispending && <div>Loading</div>}
        {Iserror && <div> Getting a error fecthing the data</div>}
      {/* To Do Tasks */}
      <div className="yts">
        {Data && <Yello indata = {Data} />}
      </div>
      <div className="inprogress">
        {Data && <InProgress indata = {Data} />}
      </div>
      <div className="Completed"></div>
      </div>
  );
};

export default Homepage;
